import{_ as l,c as i,o as r,a5 as e,j as a}from"./chunks/framework.Dtwt352Q.js";const p=JSON.parse('{"title":"v1.1.19：新增 GitLab Duo 支持与 Ask Question 工具","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.19.md","filePath":"changelog/v1.1.19.md","lastUpdated":1772014034000}'),o={name:"changelog/v1.1.19.md"};function d(h,t,n,s,b,u){return r(),i("div",null,[...t[0]||(t[0]=[e('<h1 id="v1-1-19-新增-gitlab-duo-支持与-ask-question-工具" tabindex="-1">v1.1.19：新增 GitLab Duo 支持与 Ask Question 工具 <a class="header-anchor" href="#v1-1-19-新增-gitlab-duo-支持与-ask-question-工具" aria-label="Permalink to “v1.1.19：新增 GitLab Duo 支持与 Ask Question 工具”">​</a></h1><p><strong>发布日期</strong>：2026年1月14日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新添加了 <strong>GitLab Duo Agentic Chat</strong> 支持，并在桌面应用中集成了&quot;向 Claude 提问&quot;工具。</p><hr><h2 id="新功能-gitlab-duo-支持" tabindex="-1">新功能：GitLab Duo 支持 <a class="header-anchor" href="#新功能-gitlab-duo-支持" aria-label="Permalink to “新功能：GitLab Duo 支持”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>现在可以使用 GitLab 的 AI 代码助手 GitLab Duo Agentic Chat 了。</p><h3 id="gitlab-duo-是什么" tabindex="-1">GitLab Duo 是什么？ <a class="header-anchor" href="#gitlab-duo-是什么" aria-label="Permalink to “GitLab Duo 是什么？”">​</a></h3><p>GitLab Duo 是 GitLab 内置的 AI 代码助手，提供：</p><ul><li>代码补全和生成</li><li>代码解释和重构建议</li><li>安全漏洞检测</li><li>自然语言查询代码库</li></ul><h3 id="什么时候用-gitlab-duo" tabindex="-1">什么时候用 GitLab Duo？ <a class="header-anchor" href="#什么时候用-gitlab-duo" aria-label="Permalink to “什么时候用 GitLab Duo？”">​</a></h3><table tabindex="0"><thead><tr><th>你的开发环境</th><th>推荐模型</th></tr></thead><tbody><tr><td>主要用 GitLab，公司有 Duo 订阅</td><td>✅ GitLab Duo</td></tr><tr><td>个人项目，用 GitHub</td><td>GPT-5.2 / Codex</td></tr><tr><td>企业内网，用 GitLab 自托管</td><td>✅ GitLab Duo</td></tr></tbody></table><h3 id="如何使用" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用" aria-label="Permalink to “如何使用？”">​</a></h3><p>👉 <strong>连接 GitLab Duo</strong>：</p><ol><li>输入 <code>/connect</code></li><li>选择 <strong>GitLab Duo</strong></li><li>配置你的 GitLab 访问令牌</li><li>开始使用！</li></ol><blockquote><p>💡 <strong>提示</strong>：需要你的 GitLab 实例启用了 GitLab Duo 功能。</p></blockquote><hr><h2 id="新功能-桌面应用-向-claude-提问-工具" tabindex="-1">新功能：桌面应用&quot;向 Claude 提问&quot;工具 <a class="header-anchor" href="#新功能-桌面应用-向-claude-提问-工具" aria-label="Permalink to “新功能：桌面应用&quot;向 Claude 提问&quot;工具”">​</a></h2><h3 id="这次更新了什么-1" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-1" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>桌面应用现在支持&quot;向 Claude 提问&quot;工具，让你在开发过程中随时向 Claude 寻求帮助。</p><h3 id="对你有什么好处" tabindex="-1">对你有什么好处？ <a class="header-anchor" href="#对你有什么好处" aria-label="Permalink to “对你有什么好处？”">​</a></h3><p>之前这个工具只能在 TUI 中使用，现在桌面用户也可以享受这个功能了。</p><h3 id="如何使用-1" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用-1" aria-label="Permalink to “如何使用？”">​</a></h3><p>在桌面应用中：</p><ol><li>开始一个任务</li><li>Claude 会自动识别需要向你提问的场景</li><li>在对话框中输入你的答案</li><li>继续对话</li></ol><blockquote><p>💡 <strong>用途</strong>：当 Claude 需要确认你的偏好、选择或决策时，会使用这个工具。</p></blockquote><hr><h2 id="问题修复-资源泄漏" tabindex="-1">问题修复：资源泄漏 <a class="header-anchor" href="#问题修复-资源泄漏" aria-label="Permalink to “问题修复：资源泄漏”">​</a></h2><h3 id="之前的问题" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题" aria-label="Permalink to “之前的问题”">​</a></h3><p>长时间使用 MCP（Model Context Protocol）服务器时，可能出现资源泄漏，占用过多内存。</p><h3 id="现在的情况" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况" aria-label="Permalink to “现在的情况”">​</a></h3><p>修复了两个内存泄漏问题：</p><ul><li>关闭旧的 MCP 客户端后再创建新的</li><li>实例销毁时删除 recordsByKey 中的键</li></ul><p>现在可以长期稳定使用 MCP 服务器了。</p><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>用 GitLab</td><td>✅ 升级（支持 GitLab Duo）</td></tr><tr><td>用桌面应用</td><td>✅ 升级（新增 Ask Question 工具）</td></tr><tr><td>长时间使用 MCP 服务器</td><td>✅ 升级（修复内存泄漏）</td></tr><tr><td>不符合以上情况</td><td>可以等下次</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',40),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),e('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core-核心" tabindex="-1">Core（核心） <a class="header-anchor" href="#core-核心" aria-label="Permalink to “Core（核心）”">​</a></h3><ul><li>防止代理使用无自定义的问题</li><li>改进探索代理的提示词</li><li>为提供商测试添加插件模拟</li><li>更新 webfetch 中的 User-Agent 字符串到最新 Chrome 版本</li><li>添加带进入和退出工具的计划模式</li><li>为 Codex 插件中的 GPT 5.2 Codex 添加 family 属性</li><li>添加 GitLab Duo Agentic Chat 提供商支持</li><li>实例销毁时从 recordsByKey 删除键</li><li>在重新分配前关闭现有 MCP 客户端以防止资源泄漏</li><li>为桌面应用添加 Ask Question 工具支持</li></ul><h3 id="tui-终端界面" tabindex="-1">TUI（终端界面） <a class="header-anchor" href="#tui-终端界面" aria-label="Permalink to “TUI（终端界面）”">​</a></h3><ul><li>调整 TUI 中的外部目录权限渲染</li><li>确保 TUI 中外部目录和 Bash 工具调用渲染工作目录详情</li><li>修复 MCP 认证 CLI 界面中的重复单选按钮图标</li></ul><h3 id="desktop-桌面应用" tabindex="-1">Desktop（桌面应用） <a class="header-anchor" href="#desktop-桌面应用" aria-label="Permalink to “Desktop（桌面应用）”">​</a></h3><ul><li>在 IME 检查之前处理 Shift+Enter 以防止提示输入卡住</li><li>在桌面应用的选择模型对话框中恢复供应商图标</li></ul><h3 id="社区贡献" tabindex="-1">社区贡献 <a class="header-anchor" href="#社区贡献" aria-label="Permalink to “社区贡献”">​</a></h3><ul><li>@dbpolito：桌面应用 Ask Question 工具支持</li><li>@cmdr-chara：添加 Undertale 和 Deltarune 内置主题</li><li>@vglafirov：GitLab Duo 支持</li><li>@sauerdaniel：修复 MCP 资源泄漏</li><li>以及其他 4 位贡献者</li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const g=l(o,[["render",d]]);export{p as __pageData,g as default};
